var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"꺽다리, 오늘 신작 좀비 영화라도 개봉했어?","JPN":"のっぽ、今日って新作ゾンビ映画の公開日だっけ？","ENG":"Hey Long Legs, did a new zombie movie come out today?","TWN":"高個子，今天是有新的活屍片上映嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"내가 신작 영화 개봉일까지 외우고 다니는 사람처럼 보였나?","JPN":"私が新作映画の公開日まで記憶する人間に見えるか？","ENG":"Do you think I am someone who goes around memorizing release days of new movies?","TWN":"你看我像是會記得電影上映日期的人嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"그거라도 외우고 다녀야 밥값을 하지.","JPN":"そういうのも記憶しておかないと仕事できないよ。","ENG":"Well, you gotta do something to pull your weight around here, right?","TWN":"起碼要記一下才對得起你領的薪水吧？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"네 말을 참고 들어주는 것만으로도 내 소임은 충분히 다한 것 같군.","JPN":"君の話を我慢して聞いてあげるだけでも私の役目は十分果たしている。","ENG":"Putting up with you is enough work for me.","TWN":"我光是忍受你這些話，應該就已經很對得起我的薪水。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"어련하시겠어, 총각.","JPN":"ごもっとも。","ENG":"Oof, yeah. Sorrrry.","TWN":"好，你說的都對。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"아무튼 그럼 이 좀비들은 다 뭐야? 침식체도 아니고 평범한 시체 같은데?","JPN":"とにかく、じゃあこのゾンビは何だよ？　侵食体でもないし、普通の死体に見えるけど。","ENG":"Anyway, is this all of the zombies? They look like normal corpses and not C.O.s...","TWN":"那些活屍到底是怎麼回事？我看他們不像侵蝕體，只是一般的屍體？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"글쎄…….","JPN":"さあな……","ENG":"Who knows...?","TWN":"不知道……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"차고 있는 인식표를 봐서는 철퇴 용병단들 같군.","JPN":"つけている認識票から察するに、鉄槌傭兵団のようだ。","ENG":"Looking at their dog tags, I assume these are Mace Mercenary.","TWN":"從他們身上的識別證看來，似乎是鐵鎚傭兵團的人。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"이것들이 클로디아를 쫄래쫄래 따라갔던 그 아저씨들이라고?","JPN":"これがクラウディアにぞろぞろついて行ったあのおっさんたちだってこと？","ENG":"So these are the guys that followed Claudia in here?","TWN":"你說他們就是跟著克勞迪婭的那些大叔？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"그럼 제대로 온 거네. 얼른 클로디아부터 찾으러 가자.","JPN":"じゃあ、ちゃんと到着したんだね。さっそくクラウディアから探しに行こう。","ENG":"I guess we are in the right place. Come. We must look for Claudia.","TWN":"那來得正是時候！我們快去找克勞迪婭吧！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"걔 찬송가가 아무리 기똥차도 좀비들이 들어먹진 않을 테니까.","JPN":"あいつの讃美歌がいくらすごくてもゾンビが聞くわけないもんな。","ENG":"Even if her hymns have great power, it won't work with these zombies.","TWN":"就算她詩歌唱得再好聽，活屍們也不至於吃掉她吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"성무를 위해 희생한 이들이다. 애도를 표해 줘야지.","JPN":"聖務のために犠牲になった者たちだ。哀悼しなければ。","ENG":"They have sacrificed their lives for the sacred mission. Please show some respect.","TWN":"他們都是因公殉職的，必須為他們哀悼。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"어휴. 사사건건 참견이지.","JPN":"まったく。いちいちうるさいなあ。","ENG":"Ugh... You just gotta butt in.","TWN":"真是的，不管說什麼都有意見。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"아멘, 빠빠이. 아저씨들.","JPN":"アーメン、バイバイ。おっさんたち。","ENG":"Amen. Buh-bye, misters.","TWN":"Amen，大叔們ByeBye。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"망자들을 애도하는 기도문 정도는 성의 있게 외우지 않겠나?","JPN":"死者を哀悼する祈祷文くらいは誠意を持って覚えてくれないか？","ENG":"Would you at least recite a prayer to mourn the dead?","TWN":"你就不能有誠意一點，為這些逝去的靈魂唸個哀悼文嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"기도 가지고 속이 풀리겠어? 자기들 죽인 머리통이라도 가져오면 모를까.","JPN":"祈りくらいで気が済むわけないでしょ？　自分たちを殺したやつの頭でも持ってくるならともかく。","ENG":"You think a prayer is going to let them rest in peace? It'll take at least the head of whatever did this to them.","TWN":"唸哀悼文就能夠消除他們的怨氣嗎？替他們報仇他們還開心一點吧？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"응? 왜 그래?","JPN":"うん？　どうした？","ENG":"Hmm? What?","TWN":"嗯？怎樣？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"아니. 너답지 않게 조금은 일리가 있는 지적이었다고 생각했을 뿐이다.","JPN":"いや。君にしては一理ある指摘だったと思っただけだ。","ENG":"Nothing. It surprised me that you would say something so out of character.","TWN":"沒事，只是覺得你難得說出這麼有智慧的話。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"그보다 이걸 봐라.","JPN":"それよりこれを見ろ。","ENG":"Other than that, look over here.","TWN":"先不說這些，你看。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"뭐야, 그거? 시체 안에 왕꿈틀이가 숨어 있었네?","JPN":"なに、それ？　死体の中に大王ミミズがいたんだね？","ENG":"What's that? There's a big wiggler squirming inside the corpse?","TWN":"這是什麼？屍體內竟然有大蚯蚓？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"크기는 작지만 아직 살아 있군. 질감은 나무뿌리처럼 딱딱해.","JPN":"サイズは小さいがまだ生きているな。まるで木の根のように硬い。","ENG":"They are still small, but still very much alive. And they are rather hard, like tree roots.","TWN":"是不大隻，不過它還活著，觸感像樹根一樣硬硬的。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"그리고 이것으로부터 아주 미약한 침식파가 흘러나오고 있어.","JPN":"そして、ここから微弱だが侵食波が出ている。","ENG":"I also sense miniscule amounts of Corruption ray emitting from it.","TWN":"而且還散發出微微的侵蝕波。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"그 손바닥만 한 게 침식체라고?","JPN":"あの掌サイズのやつが侵食体だってこと？","ENG":"That thing the size of your hand is a C.O.?","TWN":"那個手掌般大的東西是侵蝕體？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"아니. 아무래도 이건 어떤 침식체에게서 떨어져 나온 일종의 생체 수신기 같다.","JPN":"いや。どうやらこれはある侵食体から剥がれ落ちた一種の生体受信機のようだ。","ENG":"No. Perhaps it is a bio-receiver that has fallen off from another C.O.","TWN":"不是，應該是從某個侵蝕體身上掉下來的生物接收器。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"모체의 침식파를 받으면 생체 전류를 발산해 숙주를 조종하는 거지.","JPN":"母体の侵食波を受けると生体電流を発散し、宿主を操る。","ENG":"Thus, when it receives Corruption rays from its parent, it emits bio-electrical waves that control the host.","TWN":"接收本體的侵蝕波後，再發射生物電流來控制宿主。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"잠깐. 그 말은 클로디아도 조종당할 수 있단 뜻이야?","JPN":"待って。それってクラウディアでも操られる可能性があるってこと？","ENG":"Wait a minute. You mean this can even control Claudia?","TWN":"等等，你的意思是，克勞迪婭也很可能會受到控制嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"아니. 이 시신들처럼 침식파에 심각하게 오염되지 않는다면 인간의 면역체계도 뚫지 못할 거다.","JPN":"いや。この遺体のように侵食波の汚染が深刻でなければ、人間の免疫系も突破できないはずだ。","ENG":"No. They will not be able to penetrate the human immune system unless the host is severely contaminated by Corruption ray, as these corpses are.","TWN":"不是，若不是像這些屍體一樣，受到侵蝕波嚴重的汙染，是無法突破人體的免疫系統的。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"하지만……. 너무 늦어선 안 되겠군.","JPN":"だが……時間が経ちすぎるとだめかもしれない。","ENG":"But... This means we have to hurry.","TWN":"不過……我們必須把握時間。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"재수없는 소리 그만하고 클로디아 찾을 생각이나 해, 꺽다리.","JPN":"縁起でもないこと言ってないで、クラウディアを探すことでも考えたら？　のっぽ。","ENG":"Stop freaking me out, and think of a way to find Claudia, Long Legs.","TWN":"少說這些不吉利的話，想想要怎麼找到克勞迪婭吧，高個子。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"클로디아까지 저 꼴로 나타나면 너부터 요단강에 처박아 버리겠어.","JPN":"クラウディアまであの姿で現れたら、あんたからヨルダン川に突き落としてやるから。","ENG":"If Claudia appears in front of us like that, you'll be the first person I send across the Styx, got that?","TWN":"要是連克勞迪婭也變得像活屍一樣，我就把你扔到約旦河裡。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"안심해라. 널 맡길 사람은 클로디아 한 명뿐이니까.","JPN":"安心しろ。君を任せられる人はクラウディア一人だけだからな。","ENG":"Do not worry. Claudia is the only person who can handle you.","TWN":"放心吧，你只要負責克勞迪婭就好。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"뭐야, 아직도 좀비가 남아 있었어?","JPN":"何だよ、まだゾンビが残ってた？","ENG":"Huh?! There're still zombies out here?","TWN":"搞什麼，還有其他活屍嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"CLARK_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"크, 크윽……! 살려…….","JPN":"く、くうっ……！　助けて……","ENG":"K-kgh...! Help-","TWN":"呃呃……！救我……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"신디, 물러서라! 생존자다!","JPN":"シンディ、下がれ！　生存者だ！","ENG":"Cindy, get back! A survivor!","TWN":"辛蒂，住手！他是倖存者！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"……이상한 대목이로군요.","JPN":"……おかしな一節ですね。","ENG":"What a strange occurrence...","TWN":"……這段有點奇怪。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"언니 사회에 불만 많지? 뭐가 그렇게 이상해?","JPN":"お姉さん、社会に不満多いでしょ？　何がそんなにおかしいの？","ENG":"You don't go out much, do you? What's so strange about that?","TWN":"姊姊，你是不是反社會人格？哪有什麼好奇怪的？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"어떻게 알아챘을까요? 손에 쥐지 않으면 모를 만큼 미약한 침식파를 발산한다는 그…….","JPN":"どうやって気付いたのでしょうか。手に握らないとわからないほどの微弱な侵食波を発するという、その……","ENG":"How did he find out? If the Corruption ray was so miniscule without touching that...","TWN":"你是怎麼發現的？發射微弱侵蝕波的那個……"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"왕꿈틀이를?","JPN":"大王ミミズ？","ENG":"Big wiggler?","TWN":"你說大蚯蚓？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"시체를 조종하는 습성치고는 조금 깜찍한 이름 같군요.","JPN":"死体を操る習性にしては可愛いらしい名前ですね。","ENG":"That is a rather cute name for something that can take control of the corpse.","TWN":"以可控制屍體來說，這個名字似乎有點可愛，"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 일반에 알려졌던 적 없는 침식체에 대해 단번에 생체 구조까지 파악하긴 쉽지 않죠.","JPN":"ですが、一般に知られていない侵食体の生体構造まで一目で把握するのはそう簡単ではないはずです。","ENG":"However, identifying the biological structure of a C.O. that is not publicly known is difficult.","TWN":"不過連一般人都不知道的侵蝕體，應該很難一下就掌握生物結構吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"연구실도 아닌 숲 속 한복판에서라면 더더욱.","JPN":"研究室でもない、森の真ん中でなら尚更。","ENG":"Even more so, it was carried out in the depths of the forest rather than in a laboratory.","TWN":"更何況又不是身在研究室裡，而是在森林正中央。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"무슨 요술을 부렸는지 낸들 알아?\xA0","JPN":"どんな魔法を使ったのかなんて知るもんか。\xA0","ENG":"How would I know what kind of magic he used?\xA0","TWN":"可能是有施什麼巫術吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"아무튼 생존자는 꺽다리가 진정시켰어. 뒷일은 무전 받고 온 구조대에게 넘겼고.","JPN":"とにかく生存者はのっぽが落ち着かせたんだ。後は無線で来た救助隊に任せたし。","ENG":"Anyway, Long Legs calmed the survivor down. Then we left the rest to the radioed rescue team.","TWN":"總之高個子讓倖存者冷靜下來後收到無線電，就轉交給前來的救援隊處理。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"생존자의 성함은…… 클락 헤밍턴.","JPN":"生存者の名前は……クラーク・ハミントン。","ENG":"The name of the survivor is... Clark Hammington.","TWN":"倖存者的姓名是……克拉克·海明頓。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이송을 맡았던 자매님의 증언으로는 숲을 벗어나자마자 어디론가 도망쳤다더군요.","JPN":"移送を担当していたシスターの証言では、森を抜け出るなりどこかに逃げたらしいです。","ENG":"According to one of the Sisters in charge of transportation, he ran away as soon as they got out of the forest.","TWN":"根據負責移送的姊妹的證詞，一離開森林後，他便立刻逃得不見蹤影。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"주사 맞기가 많이 싫었나 보네. 다 큰 어른이.","JPN":"注射されるのがよほどイヤだったんだね。大の大人のくせに。","ENG":"I guess even grown ups don't like getting pricked by needles.","TWN":"他可能很害怕打針吧，明明塊頭那麼大。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"확보한 증언에 따르면 주사 때문만은 아니었습니다.","JPN":"証言によれば、注射のせいだけではありませんでした。","ENG":"Based on the obtained testimonies, it was not just about getting a shot.","TWN":"根據我們得到的證詞，並非只是因為害怕打針。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그 남자와 클락 형제 사이에 어떤 대화가 오갔는지는 기억하십니까?","JPN":"あの男とクラーク兄弟がどんな会話を交わしていたか、覚えていますか？","ENG":"Do you recall what that man and Clark talked about?","TWN":"你記得那男的和克拉克弟兄之間的對話嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"글쎄. 난 둘이 노닥거리는 동안 좀비 나타나나 지키고 있었거든.","JPN":"さあ？　あたしは二人が遊んでる間にゾンビが出ないか見守ってたからな。","ENG":"Hmm... Well, I was on watch for zombies while they were talking.","TWN":"我不知道，他們二個在對話的時候，我正在忙著對付活屍呢。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"아. 그래. 꺽다리가 남자 말을 듣더니 클로디아가 사교도들 마을에 있을 것 같다고 했어.","JPN":"あ。そうだ。のっぽがあの男の話を聞いて、クラウディアが邪教徒の村にいそうだって言ってた。","ENG":"Oh, right! After talking with the guy, Long Legs said that Claudia might be at the village with the cultists.","TWN":"喔，有啦，高個子聽完他的話後，說克勞迪婭應該就在邪教徒的村莊。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"마침내 성무의 근원지로군요.","JPN":"いよいよ聖務の根源地ですね。","ENG":"Finally back at the origin of the sacred mission.","TWN":"正好就是聖務的地點呢。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"마을의 분위기는 어땠나요?","JPN":"村の雰囲気はどうでしたか？","ENG":"What was the atmosphere like in that village?","TWN":"村莊的氛圍如何？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"평화롭더라고. 짜증 날 만큼.","JPN":"平和だったね。イライラするほど。","ENG":"It was peaceful. Annoyingly a bit too peaceful.","TWN":"安靜到令人心煩的感覺。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"어째서죠?","JPN":"どうしてですか？","ENG":"How come?","TWN":"怎麼說？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"내가 이 짓거리 하면서 느낀 게 있거든.","JPN":"この仕事やってて、思ったことがあるんだ。","ENG":"There's one thing I've learned doing this job.","TWN":"我當時發現，"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"동네 근처에서 전기톱 소리가 하늘을 찌르는데 거기 사는 놈들이 태평한 건 둘 중 하나야.","JPN":"村の近くでチェーンソーの音が響いてるのに、そこの住民が呑気にしてる理由なんて二つのうちのどっちかだよ。","ENG":"It's one of two that people look peaceful while even they hear a chainsaw whirring close by.","TWN":"雖然電鋸聲劃破天際，村裡的人卻都一副天下太平的表情，這只有二種可能。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"단체로 미쳐 가는 중이거나. 아니면 벌써 미쳤거나.","JPN":"みんで狂ってる最中か、それとももうすでに狂ってるか。","ENG":"They're all going crazy, or they’re already crazy.","TWN":"一種是他們集體逐漸精神錯亂，"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"그리고…… 걔들은 진작에 미쳐 버린 쪽이었어.","JPN":"そして……あいつらはすでに狂ってる方だったんだ。","ENG":"And... They were surely the latter.","TWN":"另一種是……他們早就已經精神錯亂。"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};